@section('script')
<script>
 
      var options = {
        chart: {
            height: 295,
            type: "bar",
            toolbar: {
                show: !1
            }
        },
        plotOptions: {
            bar: {
                horizontal: !1,
                endingShape: "rounded",
                columnWidth: "30%"
            }
        },
        dataLabels: {
            enabled: !1
        },
        stroke: {
            show: !0,
            width: 2,
            colors: ["transparent"]
        },
        colors: ["#663e32"],
        series: [ {
            name: "Total",
            data: [ @foreach($orders as $key => $value){{ $value . ',' }} @endforeach]
        }],
        xaxis: {
            categories: [ @foreach($orders as $key => $value){!! '\'' .$key . '\',' !!} @endforeach  ],
            axisBorder: {
                show: !0,
                color: "#bec7e0"
            },
            axisTicks: {
                show: !0,
                color: "#bec7e0"
            }
        },
        legend: {
            offsetY: 6
        },
        yaxis: {
            title: {
                text: "Orders Count"
            }
        },
        fill: {
            opacity: 1
        },
        grid: {
            row: {
                colors: ["transparent", "transparent"],
                opacity: .2
            },
            strokeDashArray: 4
        },
        tooltip: {
            y: {
                formatter: function(e) {
                    return e + ' Orders'
                }
            }
        }
    };

    var chart = new ApexCharts(document.querySelector("#chart"), options);
    chart.render();
 
</script>
@endsection